import { useState, useRef, useEffect, useCallback } from "react";

// ── BLG Brand Assets ──────────────────────────────────────────────────────────
const BLG_LOGO_SM = "data:image/png;base64,";
const BLG_LOGO_MD = "data:image/png;base64,";

// ── Color tokens & design system ──────────────────────────────────────────────
const C = {
  bg: "#0A0D14",
  surface: "#111520",
  surfaceHigh: "#161C2D",
  border: "#1E2840",
  borderBright: "#2A3A5C",
  accent: "#00D4FF",
  accentDim: "#0099BB",
  gold: "#F5A623",
  goldDim: "#C47D0E",
  green: "#00E5A0",
  red: "#FF4D6A",
  purple: "#A855F7",
  text: "#E8EDF7",
  textMid: "#8A9BBF",
  textDim: "#4A5578",
};

const css = `
  @import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=IBM+Plex+Mono:wght@400;500&family=Inter:wght@300;400;500;600&display=swap');
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { background: ${C.bg}; color: ${C.text}; font-family: 'Inter', sans-serif; overflow-x: hidden; }
  ::-webkit-scrollbar { width: 4px; height: 4px; }
  ::-webkit-scrollbar-track { background: ${C.surface}; }
  ::-webkit-scrollbar-thumb { background: ${C.borderBright}; border-radius: 2px; }

  .platform-shell { display: flex; min-height: 100vh; }
  
  /* SIDEBAR */
  .sidebar { width: 220px; min-width: 220px; background: ${C.surface}; border-right: 1px solid ${C.border}; display: flex; flex-direction: column; padding: 0; position: sticky; top: 0; height: 100vh; overflow-y: auto; z-index: 100; }
  .sidebar-logo { padding: 20px 20px 16px; border-bottom: 1px solid ${C.border}; }
  .sidebar-logo .brand { font-family: 'Syne', sans-serif; font-weight: 800; font-size: 15px; letter-spacing: .08em; color: ${C.accent}; }
  .sidebar-logo .sub { font-family: 'IBM Plex Mono', monospace; font-size: 9px; color: ${C.textDim}; letter-spacing: .12em; margin-top: 2px; }
  .sidebar-section { padding: 16px 12px 8px; }
  .sidebar-section-label { font-family: 'IBM Plex Mono', monospace; font-size: 9px; letter-spacing: .14em; color: ${C.textDim}; text-transform: uppercase; margin-bottom: 8px; padding-left: 8px; }
  .nav-item { display: flex; align-items: center; gap: 10px; padding: 9px 12px; border-radius: 8px; cursor: pointer; transition: all .15s; font-size: 13px; font-weight: 500; color: ${C.textMid}; border: 1px solid transparent; }
  .nav-item:hover { background: ${C.surfaceHigh}; color: ${C.text}; }
  .nav-item.active { background: rgba(0,212,255,.08); border-color: rgba(0,212,255,.2); color: ${C.accent}; }
  .nav-item .nav-icon { font-size: 14px; width: 16px; text-align: center; }
  .nav-badge { margin-left: auto; background: ${C.accent}; color: ${C.bg}; font-size: 9px; font-weight: 700; padding: 2px 6px; border-radius: 10px; font-family: 'IBM Plex Mono', monospace; }
  .nav-badge.gold { background: ${C.gold}; }
  .sidebar-footer { margin-top: auto; padding: 16px; border-top: 1px solid ${C.border}; }
  .pipeline-tag { display: inline-flex; align-items: center; gap: 6px; background: rgba(245,166,35,.1); border: 1px solid rgba(245,166,35,.3); border-radius: 6px; padding: 6px 10px; font-size: 11px; font-family: 'IBM Plex Mono', monospace; color: ${C.gold}; }
  .pipeline-dot { width: 6px; height: 6px; border-radius: 50%; background: ${C.gold}; animation: pulse 1.5s infinite; }
  @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:.4} }

  /* MAIN */
  .main-content { flex: 1; display: flex; flex-direction: column; min-width: 0; }
  .topbar { padding: 16px 28px; border-bottom: 1px solid ${C.border}; background: ${C.surface}; display: flex; align-items: center; gap: 16px; position: sticky; top: 0; z-index: 90; }
  .topbar-title { font-family: 'Syne', sans-serif; font-weight: 700; font-size: 18px; color: ${C.text}; }
  .topbar-sub { font-size: 12px; color: ${C.textDim}; font-family: 'IBM Plex Mono', monospace; margin-top: 2px; }
  .topbar-right { margin-left: auto; display: flex; align-items: center; gap: 12px; }
  .status-chip { display: inline-flex; align-items: center; gap: 6px; padding: 5px 12px; border-radius: 20px; font-size: 11px; font-weight: 600; font-family: 'IBM Plex Mono', monospace; }
  .status-chip.qual { background: rgba(245,166,35,.1); border: 1px solid rgba(245,166,35,.3); color: ${C.gold}; }
  .status-chip.active { background: rgba(0,229,160,.1); border: 1px solid rgba(0,229,160,.3); color: ${C.green}; }
  .page-body { padding: 24px 28px; flex: 1; }

  /* TABS */
  .tab-bar { display: flex; gap: 4px; border-bottom: 1px solid ${C.border}; margin-bottom: 24px; }
  .tab-btn { padding: 10px 18px; font-size: 12px; font-weight: 600; letter-spacing: .04em; cursor: pointer; border: none; background: transparent; color: ${C.textDim}; border-bottom: 2px solid transparent; margin-bottom: -1px; transition: all .15s; font-family: 'Inter', sans-serif; }
  .tab-btn:hover { color: ${C.text}; }
  .tab-btn.active { color: ${C.accent}; border-bottom-color: ${C.accent}; }

  /* CARDS */
  .card { background: ${C.surface}; border: 1px solid ${C.border}; border-radius: 12px; padding: 20px; }
  .card-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 16px; }
  .card-title { font-family: 'Syne', sans-serif; font-weight: 700; font-size: 14px; color: ${C.text}; }
  .card-sub { font-size: 11px; color: ${C.textDim}; font-family: 'IBM Plex Mono', monospace; margin-top: 3px; }

  /* BUTTONS */
  .btn { display: inline-flex; align-items: center; gap: 8px; padding: 9px 18px; border-radius: 8px; font-size: 12px; font-weight: 600; cursor: pointer; border: none; transition: all .15s; font-family: 'Inter', sans-serif; letter-spacing: .02em; }
  .btn-primary { background: ${C.accent}; color: ${C.bg}; }
  .btn-primary:hover { background: #33DDFF; transform: translateY(-1px); box-shadow: 0 4px 16px rgba(0,212,255,.3); }
  .btn-secondary { background: ${C.surfaceHigh}; color: ${C.text}; border: 1px solid ${C.border}; }
  .btn-secondary:hover { border-color: ${C.borderBright}; background: ${C.border}; }
  .btn-gold { background: ${C.gold}; color: ${C.bg}; }
  .btn-gold:hover { background: #F7B84A; transform: translateY(-1px); }
  .btn-ghost { background: transparent; color: ${C.textMid}; border: 1px solid ${C.border}; }
  .btn-ghost:hover { color: ${C.text}; border-color: ${C.borderBright}; }
  .btn-sm { padding: 6px 12px; font-size: 11px; }
  .btn-danger { background: rgba(255,77,106,.15); color: ${C.red}; border: 1px solid rgba(255,77,106,.3); }
  .btn-danger:hover { background: rgba(255,77,106,.25); }

  /* INPUTS */
  .input-group { display: flex; flex-direction: column; gap: 6px; }
  .input-label { font-size: 11px; font-weight: 600; color: ${C.textMid}; letter-spacing: .06em; text-transform: uppercase; font-family: 'IBM Plex Mono', monospace; }
  .input, select.input, textarea.input { background: ${C.surfaceHigh}; border: 1px solid ${C.border}; border-radius: 8px; padding: 10px 14px; font-size: 13px; color: ${C.text}; font-family: 'Inter', sans-serif; outline: none; transition: border-color .15s; width: 100%; }
  .input:focus, select.input:focus, textarea.input:focus { border-color: ${C.accent}; box-shadow: 0 0 0 3px rgba(0,212,255,.08); }
  select.input option { background: ${C.surfaceHigh}; }
  textarea.input { resize: vertical; min-height: 80px; }

  /* GRID */
  .grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
  .grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 16px; }
  .grid-4 { display: grid; grid-template-columns: repeat(4,1fr); gap: 16px; }
  .col-span-2 { grid-column: span 2; }
  .col-span-3 { grid-column: span 3; }

  /* METRIC TILES */
  .metric-tile { background: ${C.surface}; border: 1px solid ${C.border}; border-radius: 12px; padding: 18px 20px; position: relative; overflow: hidden; }
  .metric-tile::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 2px; }
  .metric-tile.cyan::before { background: linear-gradient(90deg, ${C.accent}, transparent); }
  .metric-tile.gold::before { background: linear-gradient(90deg, ${C.gold}, transparent); }
  .metric-tile.green::before { background: linear-gradient(90deg, ${C.green}, transparent); }
  .metric-tile.red::before { background: linear-gradient(90deg, ${C.red}, transparent); }
  .metric-tile.purple::before { background: linear-gradient(90deg, ${C.purple}, transparent); }
  .metric-label { font-size: 10px; font-weight: 600; letter-spacing: .1em; text-transform: uppercase; color: ${C.textDim}; font-family: 'IBM Plex Mono', monospace; margin-bottom: 8px; }
  .metric-value { font-family: 'Syne', sans-serif; font-weight: 800; font-size: 26px; color: ${C.text}; line-height: 1; }
  .metric-value.cyan { color: ${C.accent}; }
  .metric-value.gold { color: ${C.gold}; }
  .metric-value.green { color: ${C.green}; }
  .metric-value.red { color: ${C.red}; }
  .metric-delta { font-size: 11px; color: ${C.textDim}; margin-top: 6px; font-family: 'IBM Plex Mono', monospace; }
  .metric-delta.up { color: ${C.green}; }
  .metric-delta.down { color: ${C.red}; }

  /* TABLE */
  .data-table { width: 100%; border-collapse: collapse; }
  .data-table th { font-size: 10px; font-weight: 700; letter-spacing: .1em; text-transform: uppercase; color: ${C.textDim}; padding: 10px 14px; text-align: left; border-bottom: 1px solid ${C.border}; font-family: 'IBM Plex Mono', monospace; }
  .data-table td { padding: 12px 14px; font-size: 13px; border-bottom: 1px solid rgba(30,40,64,.6); color: ${C.text}; vertical-align: middle; }
  .data-table tr:hover td { background: rgba(255,255,255,.02); }
  .data-table tr:last-child td { border-bottom: none; }

  /* BADGE */
  .badge { display: inline-flex; align-items: center; gap: 4px; padding: 3px 10px; border-radius: 20px; font-size: 10px; font-weight: 700; font-family: 'IBM Plex Mono', monospace; letter-spacing: .06em; }
  .badge-cyan { background: rgba(0,212,255,.1); color: ${C.accent}; border: 1px solid rgba(0,212,255,.2); }
  .badge-gold { background: rgba(245,166,35,.1); color: ${C.gold}; border: 1px solid rgba(245,166,35,.2); }
  .badge-green { background: rgba(0,229,160,.1); color: ${C.green}; border: 1px solid rgba(0,229,160,.2); }
  .badge-red { background: rgba(255,77,106,.1); color: ${C.red}; border: 1px solid rgba(255,77,106,.2); }
  .badge-purple { background: rgba(168,85,247,.1); color: ${C.purple}; border: 1px solid rgba(168,85,247,.2); }
  .badge-gray { background: rgba(138,155,191,.1); color: ${C.textMid}; border: 1px solid rgba(138,155,191,.2); }

  /* DOCUMENT UPLOAD */
  .drop-zone { border: 2px dashed ${C.border}; border-radius: 12px; padding: 40px; text-align: center; cursor: pointer; transition: all .2s; background: ${C.surfaceHigh}; }
  .drop-zone:hover, .drop-zone.over { border-color: ${C.accent}; background: rgba(0,212,255,.04); }
  .drop-zone-icon { font-size: 36px; margin-bottom: 12px; }
  .drop-zone-text { font-size: 14px; color: ${C.textMid}; margin-bottom: 6px; }
  .drop-zone-sub { font-size: 11px; color: ${C.textDim}; font-family: 'IBM Plex Mono', monospace; }

  /* PROGRESS */
  .progress-bar { height: 4px; background: ${C.border}; border-radius: 2px; overflow: hidden; }
  .progress-fill { height: 100%; border-radius: 2px; transition: width .5s ease; }
  .progress-fill.cyan { background: linear-gradient(90deg, ${C.accentDim}, ${C.accent}); }
  .progress-fill.gold { background: linear-gradient(90deg, ${C.goldDim}, ${C.gold}); }
  .progress-fill.green { background: linear-gradient(90deg, #00B577, ${C.green}); }
  .progress-fill.red { background: linear-gradient(90deg, #CC2040, ${C.red}); }

  /* TCO MATRIX */
  .tco-header { background: linear-gradient(135deg, rgba(0,212,255,.08), rgba(168,85,247,.08)); border: 1px solid rgba(0,212,255,.15); border-radius: 10px; padding: 14px 18px; margin-bottom: 16px; }
  .tco-vendor-col { min-width: 160px; }
  .tco-highlight { background: rgba(0,229,160,.06); }
  .tco-best { color: ${C.green}; font-weight: 700; }
  .tco-worst { color: ${C.red}; }
  .comparison-bar { height: 6px; border-radius: 3px; margin-top: 4px; transition: width .6s ease; }

  /* AI CHAT */
  .chat-container { display: flex; flex-direction: column; height: 560px; }
  .chat-messages { flex: 1; overflow-y: auto; padding: 16px; display: flex; flex-direction: column; gap: 12px; }
  .chat-msg { display: flex; gap: 10px; max-width: 85%; }
  .chat-msg.user { flex-direction: row-reverse; align-self: flex-end; }
  .chat-avatar { width: 28px; height: 28px; min-width: 28px; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 700; }
  .chat-avatar.ai { background: linear-gradient(135deg, rgba(0,212,255,.2), rgba(168,85,247,.2)); border: 1px solid rgba(0,212,255,.3); color: ${C.accent}; }
  .chat-avatar.user { background: linear-gradient(135deg, rgba(245,166,35,.2), rgba(245,166,35,.1)); border: 1px solid rgba(245,166,35,.3); color: ${C.gold}; }
  .chat-bubble { background: ${C.surfaceHigh}; border: 1px solid ${C.border}; border-radius: 10px; padding: 12px 14px; font-size: 13px; line-height: 1.6; color: ${C.text}; }
  .chat-bubble.user { background: rgba(0,212,255,.06); border-color: rgba(0,212,255,.2); }
  .chat-bubble.ai { }
  .chat-input-row { display: flex; gap: 10px; padding: 16px; border-top: 1px solid ${C.border}; }
  .chat-input { flex: 1; background: ${C.surfaceHigh}; border: 1px solid ${C.border}; border-radius: 8px; padding: 10px 14px; font-size: 13px; color: ${C.text}; outline: none; font-family: 'Inter', sans-serif; }
  .chat-input:focus { border-color: ${C.accent}; }
  .typing-dot { display: inline-block; width: 6px; height: 6px; border-radius: 50%; background: ${C.accentDim}; margin: 0 2px; animation: typing .8s infinite; }
  .typing-dot:nth-child(2) { animation-delay: .15s; }
  .typing-dot:nth-child(3) { animation-delay: .3s; }
  @keyframes typing { 0%,60%,100%{transform:translateY(0)} 30%{transform:translateY(-6px)} }

  /* CONTRACT TERMS */
  .term-row { display: flex; align-items: flex-start; gap: 12px; padding: 12px 0; border-bottom: 1px solid rgba(30,40,64,.5); }
  .term-row:last-child { border-bottom: none; }
  .term-icon { width: 32px; height: 32px; min-width: 32px; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 14px; }
  .term-key { font-size: 12px; font-weight: 600; color: ${C.textMid}; margin-bottom: 3px; font-family: 'IBM Plex Mono', monospace; }
  .term-val { font-size: 14px; color: ${C.text}; font-weight: 500; }
  .term-risk { font-size: 10px; margin-top: 4px; font-family: 'IBM Plex Mono', monospace; }

  /* FINANCIAL ENGINE */
  .fin-row { display: flex; align-items: center; justify-content: space-between; padding: 10px 0; border-bottom: 1px solid rgba(30,40,64,.5); }
  .fin-row:last-child { border-bottom: none; }
  .fin-label { font-size: 13px; color: ${C.textMid}; }
  .fin-value { font-family: 'IBM Plex Mono', monospace; font-size: 13px; font-weight: 600; color: ${C.text}; }
  .fin-total { font-family: 'Syne', sans-serif; font-weight: 800; font-size: 22px; }
  .validation-score { display: flex; flex-direction: column; align-items: center; justify-content: center; width: 80px; height: 80px; border-radius: 50%; border: 3px solid; position: relative; }
  .validation-score.pass { border-color: ${C.green}; color: ${C.green}; }
  .validation-score.warn { border-color: ${C.gold}; color: ${C.gold}; }
  .validation-score.fail { border-color: ${C.red}; color: ${C.red}; }
  .score-num { font-family: 'Syne', sans-serif; font-weight: 800; font-size: 22px; }
  .score-lbl { font-size: 9px; font-family: 'IBM Plex Mono', monospace; opacity: .7; }

  /* CLIENT PORTAL */
  .portal-header { background: linear-gradient(135deg, rgba(0,212,255,.06) 0%, rgba(168,85,247,.06) 50%, rgba(0,229,160,.04) 100%); border: 1px solid rgba(0,212,255,.12); border-radius: 14px; padding: 24px; margin-bottom: 20px; position: relative; overflow: hidden; }
  .portal-header::after { content: 'BLG'; position: absolute; right: -20px; bottom: -30px; font-family: 'Syne', sans-serif; font-weight: 900; font-size: 120px; color: rgba(0,212,255,.04); line-height: 1; pointer-events: none; }
  .portal-client-name { font-family: 'Syne', sans-serif; font-weight: 800; font-size: 24px; color: ${C.text}; }
  .portal-meta { font-size: 12px; color: ${C.textDim}; font-family: 'IBM Plex Mono', monospace; margin-top: 4px; }
  .milestone { display: flex; align-items: center; gap: 12px; padding: 12px 0; }
  .milestone-dot { width: 12px; height: 12px; min-width: 12px; border-radius: 50%; border: 2px solid; }
  .milestone-dot.done { background: ${C.green}; border-color: ${C.green}; }
  .milestone-dot.active { background: transparent; border-color: ${C.accent}; box-shadow: 0 0 0 3px rgba(0,212,255,.15); animation: pulse 1.5s infinite; }
  .milestone-dot.pending { background: transparent; border-color: ${C.textDim}; }
  .milestone-line { flex: 1; height: 1px; background: ${C.border}; }
  .activity-item { display: flex; gap: 12px; padding: 10px 0; border-bottom: 1px solid rgba(30,40,64,.4); }
  .activity-item:last-child { border-bottom: none; }
  .activity-icon { width: 28px; height: 28px; min-width: 28px; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 12px; }

  /* EXPORT MODAL */
  .modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,.7); backdrop-filter: blur(6px); z-index: 999; display: flex; align-items: center; justify-content: center; animation: fadeIn .2s ease; }
  @keyframes fadeIn { from{opacity:0} to{opacity:1} }
  .modal { background: ${C.surface}; border: 1px solid ${C.borderBright}; border-radius: 16px; width: 520px; max-width: 95vw; box-shadow: 0 24px 80px rgba(0,0,0,.6); animation: slideUp .2s ease; }
  @keyframes slideUp { from{transform:translateY(20px);opacity:0} to{transform:translateY(0);opacity:1} }
  .modal-header { padding: 20px 24px 0; display: flex; align-items: center; justify-content: space-between; }
  .modal-title { font-family: 'Syne', sans-serif; font-weight: 800; font-size: 18px; }
  .modal-body { padding: 20px 24px; }
  .modal-footer { padding: 0 24px 20px; display: flex; gap: 10px; justify-content: flex-end; }
  .export-option { border: 1px solid ${C.border}; border-radius: 12px; padding: 16px; cursor: pointer; transition: all .15s; background: ${C.surfaceHigh}; position: relative; }
  .export-option:hover { border-color: ${C.borderBright}; }
  .export-option.selected { border-color: rgba(0,212,255,.4); background: rgba(0,212,255,.05); }
  .export-option.selected-gold { border-color: rgba(245,166,35,.4); background: rgba(245,166,35,.05); }
  .export-option.selected-green { border-color: rgba(0,229,160,.4); background: rgba(0,229,160,.05); }
  .export-check { position: absolute; top: 10px; right: 10px; width: 18px; height: 18px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 10px; }
  .export-option-icon { font-size: 28px; margin-bottom: 8px; }
  .export-option-label { font-family: 'Syne', sans-serif; font-weight: 700; font-size: 14px; margin-bottom: 4px; }
  .export-option-sub { font-size: 11px; color: ${C.textDim}; font-family: 'IBM Plex Mono', monospace; line-height: 1.5; }
  .export-generating { display: flex; flex-direction: column; align-items: center; padding: 32px; gap: 16px; }
  .export-spinner { width: 48px; height: 48px; border: 3px solid ${C.border}; border-top-color: ${C.accent}; border-radius: 50%; animation: spin .8s linear infinite; }
  @keyframes spin { to{transform:rotate(360deg)} }
  .section-select { display: flex; flex-direction: column; gap: 8px; margin-top: 16px; }
  .section-check-row { display: flex; align-items: center; gap: 10px; padding: 8px 12px; border-radius: 8px; background: ${C.surfaceHigh}; border: 1px solid ${C.border}; cursor: pointer; }
  .section-check-row:hover { border-color: ${C.borderBright}; }
  .checkbox { width: 16px; height: 16px; border-radius: 4px; border: 2px solid ${C.borderBright}; display: flex; align-items: center; justify-content: center; font-size: 10px; flex-shrink: 0; transition: all .15s; }
  .checkbox.checked { background: ${C.accent}; border-color: ${C.accent}; color: ${C.bg}; }

  /* LOADING SHIMMER */
  .shimmer { background: linear-gradient(90deg, ${C.surfaceHigh} 25%, ${C.border} 50%, ${C.surfaceHigh} 75%); background-size: 200% 100%; animation: shimmer 1.4s infinite; border-radius: 6px; }
  @keyframes shimmer { 0%{background-position:200% 0} 100%{background-position:-200% 0} }

  /* DIVIDER */
  .divider { border: none; border-top: 1px solid ${C.border}; margin: 20px 0; }

  /* UTILITY */
  .flex { display: flex; }
  .flex-col { flex-direction: column; }
  .items-center { align-items: center; }
  .justify-between { justify-content: space-between; }
  .gap-8 { gap: 8px; }
  .gap-12 { gap: 12px; }
  .gap-16 { gap: 16px; }
  .gap-20 { gap: 20px; }
  .mt-4 { margin-top: 4px; }
  .mt-8 { margin-top: 8px; }
  .mt-12 { margin-top: 12px; }
  .mt-16 { margin-top: 16px; }
  .mt-20 { margin-top: 20px; }
  .mb-12 { margin-bottom: 12px; }
  .mb-16 { margin-bottom: 16px; }
  .text-mono { font-family: 'IBM Plex Mono', monospace; }
  .text-sm { font-size: 12px; }
  .text-xs { font-size: 11px; }
  .text-dim { color: ${C.textDim}; }
  .text-mid { color: ${C.textMid}; }
  .text-accent { color: ${C.accent}; }
  .text-gold { color: ${C.gold}; }
  .text-green { color: ${C.green}; }
  .text-red { color: ${C.red}; }
  .font-bold { font-weight: 700; }
  .font-syne { font-family: 'Syne', sans-serif; font-weight: 700; }
  .w-full { width: 100%; }
  .overflow-hidden { overflow: hidden; }
  .rounded { border-radius: 8px; }
  .p-16 { padding: 16px; }
  .opacity-50 { opacity: .5; }
  .pointer { cursor: pointer; }
  .select-none { user-select: none; }
  .separator { color: ${C.textDim}; margin: 0 8px; }
`;

