function MetricTile({ label, value, delta, color = "cyan", prefix = "", suffix = "" }) {
  return (
    <div className={`metric-tile ${color}`}>
      <div className="metric-label">{label}</div>
      <div className={`metric-value ${color}`}>{prefix}{value}{suffix}</div>
      {delta && <div className={`metric-delta ${delta.startsWith("+") || delta.startsWith("↑") ? "up" : delta.startsWith("-") || delta.startsWith("↓") ? "down" : ""}`}>{delta}</div>}
    </div>
  );
}

