// ── TAB: Vendor Proposal Matrix ────────────────────────────────────────────────
function VendorMatrix() {
  const [termMonths, setTermMonths] = useState(36);
  const [sortBy, setSortBy] = useState("tco");

  const withTCO = TCO_DATA.vendors.map(v => ({ ...v, tco: calcTCO(v, termMonths) }));
  const sorted = [...withTCO].sort((a, b) => sortBy === "tco" ? a.tco - b.tco : sortBy === "monthly" ? a.monthly - b.monthly : b.score - a.score);
  const bestTCO = Math.min(...withTCO.map(v => v.tco));
  const worstTCO = Math.max(...withTCO.map(v => v.tco));

  const fmt = (n) => "$" + n.toLocaleString();

  const rows = [
    { label: "Monthly MRC", key: "monthly", fmt: (v) => fmt(v.monthly), compare: true, lower: true },
    { label: "Installation Fee", key: "install", fmt: (v) => v.install === 0 ? "✓ Waived" : fmt(v.install), compare: false },
    { label: "Annual Rate Escalation", key: "escalation", fmt: (v) => `${v.escalation}%`, compare: true, lower: true },
    { label: "ETF (Early Termination)", key: "etf", fmt: (v) => fmt(v.etf), compare: true, lower: true },
    { label: "Support & Maintenance", key: "support", fmt: (v) => fmt(v.support) + "/yr", compare: true, lower: true },
    { label: `${termMonths}-Mo TCO`, key: "tco", fmt: (v) => fmt(v.tco), compare: true, lower: true, highlight: true },
    { label: "BLG Vendor Score", key: "score", fmt: (v) => v.score + " / 100", compare: true, lower: false },
  ];

  return (
    <div>
      <div className="grid-4 mb-16">
        <MetricTile label="Vendors Compared" value="4" color="cyan" />
        <MetricTile label={`${termMonths}-Mo Best TCO`} value={fmt(bestTCO)} color="green" delta="Lumen Technologies" />
        <MetricTile label="Max Savings vs Worst" value={fmt(worstTCO - bestTCO)} color="gold" delta="vs Comcast" />
        <MetricTile label="Avg Vendor Score" value={Math.round(withTCO.reduce((a, b) => a + b.score, 0) / withTCO.length)} suffix="/100" color="purple" />
      </div>

      <div className="card">
        <div className="card-header">
          <div><div className="card-title">Vendor Comparison Matrix</div><div className="card-sub">Side-by-side TCO analysis</div></div>
          <div className="flex items-center gap-12">
            <div className="flex items-center gap-8">
              <span className="text-xs text-mono text-mid">Term:</span>
              {[36, 60].map(m => (
                <button
                  key={m}
                  onClick={() => setTermMonths(m)}
                  style={{
                    padding: "5px 14px",
                    borderRadius: 6,
                    border: `1px solid ${termMonths === m ? C.accent : C.border}`,
                    background: termMonths === m ? "rgba(0,212,255,.1)" : C.surfaceHigh,
                    color: termMonths === m ? C.accent : C.textMid,
                    cursor: "pointer",
                    fontSize: 12,
                    fontWeight: 600,
                    fontFamily: "'IBM Plex Mono', monospace",
                  }}
                >{m} Mo</button>
              ))}
            </div>
            <div className="flex items-center gap-8">
              <span className="text-xs text-mono text-mid">Sort:</span>
              {[["tco", "TCO"], ["monthly", "MRC"], ["score", "Score"]].map(([k, l]) => (
                <button
                  key={k}
                  onClick={() => setSortBy(k)}
                  style={{
                    padding: "5px 12px",
                    borderRadius: 6,
                    border: `1px solid ${sortBy === k ? C.gold : C.border}`,
                    background: sortBy === k ? "rgba(245,166,35,.1)" : C.surfaceHigh,
                    color: sortBy === k ? C.gold : C.textMid,
                    cursor: "pointer",
                    fontSize: 11,
                    fontWeight: 600,
                    fontFamily: "'IBM Plex Mono', monospace",
                  }}
                >{l}</button>
              ))}
            </div>
            <button className="btn btn-primary btn-sm">📊 Export</button>
          </div>
        </div>

        <div style={{ overflowX: "auto" }}>
          <table className="data-table w-full">
            <thead>
              <tr>
                <th style={{ minWidth: 180 }}>Metric</th>
                {sorted.map((v, i) => (
                  <th key={v.id} style={{ textAlign: "center", minWidth: 160 }}>
                    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 4 }}>
                      <div style={{ fontSize: 16 }}>{v.logo}</div>
                      <div style={{ color: C.text, fontSize: 11 }}>{v.name}</div>
                      {i === 0 && <span className="badge badge-green" style={{ fontSize: 9 }}>⭐ BEST {sortBy.toUpperCase()}</span>}
                    </div>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {rows.map((row, ri) => (
                <tr key={ri} style={row.highlight ? { background: "rgba(0,229,160,.03)" } : {}}>
                  <td>
                    <span style={{ fontWeight: row.highlight ? 700 : 400, color: row.highlight ? C.green : C.textMid, fontFamily: row.highlight ? "'Syne', sans-serif" : "inherit", fontSize: row.highlight ? 13 : 13 }}>
                      {row.highlight ? "🏆 " : ""}{row.label}
                    </span>
                  </td>
                  {sorted.map((v) => {
                    const val = row.fmt(v);
                    const isBest = row.compare && (row.lower ? v[row.key] === Math.min(...withTCO.map(x => x[row.key])) : v[row.key] === Math.max(...withTCO.map(x => x[row.key])));
                    const isWorst = row.compare && (row.lower ? v[row.key] === Math.max(...withTCO.map(x => x[row.key])) : v[row.key] === Math.min(...withTCO.map(x => x[row.key])));
                    return (
                      <td key={v.id} style={{ textAlign: "center" }}>
                        <div style={{ fontFamily: row.highlight ? "'Syne', sans-serif" : "'IBM Plex Mono', monospace", fontWeight: row.highlight ? 800 : 500, fontSize: row.highlight ? 16 : 13, color: isBest ? C.green : isWorst ? C.red : C.text }}>
                          {val}
                        </div>
                        {row.compare && row.key !== "score" && (
                          <div style={{ marginTop: 4, height: 4, background: C.border, borderRadius: 2, overflow: "hidden" }}>
                            <div style={{
                              height: "100%",
                              width: `${((v[row.key] - Math.min(...withTCO.map(x => x[row.key]))) / (Math.max(...withTCO.map(x => x[row.key])) - Math.min(...withTCO.map(x => x[row.key])) || 1)) * 100}%`,
                              background: isBest ? C.green : isWorst ? C.red : C.gold,
                              borderRadius: 2,
                            }} />
                          </div>
                        )}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div style={{ marginTop: 20, padding: "14px 16px", background: "rgba(0,229,160,.06)", border: "1px solid rgba(0,229,160,.2)", borderRadius: 10 }}>
          <div className="flex items-center gap-10">
            <span style={{ fontSize: 18 }}>💡</span>
            <div>
              <div style={{ fontSize: 13, fontWeight: 600, color: C.green }}>BLG Recommendation — {termMonths}-Month Term</div>
              <div style={{ fontSize: 12, color: C.textMid, marginTop: 4 }}>
                <strong style={{ color: C.text }}>Lumen Technologies</strong> delivers the lowest {termMonths}-month TCO at <strong style={{ color: C.green }}>{fmt(calcTCO(TCO_DATA.vendors[1], termMonths))}</strong>,
                saving <strong style={{ color: C.accent }}>{fmt(calcTCO(TCO_DATA.vendors[0], termMonths) - calcTCO(TCO_DATA.vendors[1], termMonths))}</strong> vs Comcast over the term.
                Negotiate waiver of the $350 install fee and lock 2.5% escalation cap in writing.
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── TAB: Financial Validation Engine ──────────────────────────────────────────
function FinancialEngine() {
  const [inputs, setInputs] = useState({
    currentMRC: "2847",
    proposedMRC: "2650",
    termMonths: "36",
    installFee: "350",
    escalation: "2.5",
    etfRisk: "4770",
    implementationCost: "0",
  });

  const set = (k, v) => setInputs(p => ({ ...p, [k]: v }));

  const cur = parseFloat(inputs.currentMRC) || 0;
  const prop = parseFloat(inputs.proposedMRC) || 0;
  const term = parseInt(inputs.termMonths) || 36;
  const install = parseFloat(inputs.installFee) || 0;
  const esc = parseFloat(inputs.escalation) || 0;
  const impl = parseFloat(inputs.implementationCost) || 0;

  const mrcSavings = (cur - prop) * term;
  const escalationCost = prop * (esc / 100) * term * 0.5;
  const netSavings = mrcSavings - install - impl;
  const roi = netSavings > 0 ? ((netSavings / (install + impl + 0.01)) * 100).toFixed(0) : 0;
  const payback = install > 0 ? (install / Math.max(cur - prop, 0.01)).toFixed(1) : 0;
  const annualized = (netSavings / (term / 12)).toFixed(0);

  const score = netSavings > 5000 ? (roi > 500 ? 96 : 85) : netSavings > 0 ? 72 : 45;
  const scoreState = score >= 85 ? "pass" : score >= 65 ? "warn" : "fail";
  const scoreLabel = score >= 85 ? "APPROVED" : score >= 65 ? "REVIEW" : "REJECT";

  const validations = [
    { label: "MRC Reduction Verified", pass: prop < cur, detail: prop < cur ? `↓ $${(cur - prop).toFixed(2)}/mo` : "No savings" },
    { label: "Positive Net Savings", pass: netSavings > 0, detail: `$${netSavings.toLocaleString()} over ${term} months` },
    { label: "Install Fee Threshold (<$1K)", pass: install < 1000, detail: install === 0 ? "✓ Waived" : `$${install}` },
    { label: "Escalation Rate Acceptable (<3%)", pass: esc < 3.0, detail: `${esc}% annual` },
    { label: "ROI Target Met (>200%)", pass: parseFloat(roi) > 200 || install === 0, detail: install === 0 ? "N/A — No upfront cost" : `${roi}% ROI` },
    { label: "Payback Period (<12 Months)", pass: parseFloat(payback) < 12 || install === 0, detail: install === 0 ? "Immediate" : `${payback} months` },
  ];

  return (
    <div>
      <div className="grid-4 mb-16">
        <MetricTile label={`${term}-Mo Net Savings`} value={"$" + Math.max(0, netSavings).toLocaleString()} delta={netSavings > 0 ? "↑ Positive ROI" : "⚠️ Review required"} color={netSavings > 0 ? "green" : "red"} />
        <MetricTile label="Annual Savings" value={"$" + Math.max(0, parseInt(annualized)).toLocaleString()} delta="Annualized" color="cyan" />
        <MetricTile label="ROI" value={install === 0 ? "∞" : roi} suffix={install > 0 ? "%" : ""} delta={install === 0 ? "No upfront cost" : `${payback} mo payback`} color="gold" />
        <MetricTile label="Validation Score" value={score} suffix="/100" delta={scoreLabel} color={scoreState === "pass" ? "green" : scoreState === "warn" ? "gold" : "red"} />
      </div>

      <div className="grid-2 gap-20">
        <div className="card">
          <div className="card-header">
            <div><div className="card-title">Financial Inputs</div><div className="card-sub">Deal economics calculator</div></div>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
            {[
              ["currentMRC", "Current Monthly Rate (MRC)", "$"],
              ["proposedMRC", "Proposed Monthly Rate", "$"],
              ["termMonths", "Contract Term (Months)", ""],
              ["installFee", "Installation / Setup Fee", "$"],
              ["escalation", "Annual Rate Escalation (%)", ""],
              ["etfRisk", "Early Termination Fee (ETF)", "$"],
              ["implementationCost", "Implementation / Migration Cost", "$"],
            ].map(([key, label, pre]) => (
              <div key={key} className="input-group">
                <label className="input-label">{label}</label>
                <div style={{ position: "relative" }}>
                  {pre && <span style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: C.textDim, fontSize: 13, fontFamily: "'IBM Plex Mono', monospace" }}>{pre}</span>}
                  <input
                    type="number"
                    className="input"
                    style={pre ? { paddingLeft: 22 } : {}}
                    value={inputs[key]}
                    onChange={e => set(key, e.target.value)}
                  />
                </div>
              </div>
            ))}
            <button className="btn btn-primary w-full mt-8">🔄 Recalculate</button>
          </div>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div className="card">
            <div className="card-header">
              <div><div className="card-title">Savings Breakdown</div><div className="card-sub">{term}-month projection</div></div>
              <div className={`validation-score ${scoreState}`}>
                <div className="score-num">{score}</div>
                <div className="score-lbl">{scoreLabel}</div>
              </div>
            </div>
            {[
              ["Gross MRC Savings", "$" + mrcSavings.toLocaleString(), mrcSavings > 0],
              ["Installation Fee", install > 0 ? "-$" + install : "✓ Waived", install === 0],
              ["Implementation Cost", impl > 0 ? "-$" + impl : "N/A", impl === 0],
              ["Escalation Impact", "-$" + Math.round(escalationCost).toLocaleString(), false],
            ].map(([label, value, good], i) => (
              <div key={i} className="fin-row">
                <span className="fin-label">{label}</span>
                <span className="fin-value" style={{ color: good ? C.green : value.startsWith("-") ? C.red : C.text }}>{value}</span>
              </div>
            ))}
            <hr className="divider" />
            <div className="fin-row">
              <span className="fin-label font-bold" style={{ color: C.text }}>Net {term}-Month Savings</span>
              <span className={`fin-total ${netSavings > 0 ? "text-green" : "text-red"}`}>${Math.max(0, netSavings).toLocaleString()}</span>
            </div>
          </div>

          <div className="card">
            <div className="card-header"><div className="card-title">Validation Checks</div></div>
            {validations.map((v, i) => (
              <div key={i} className="flex items-center gap-10" style={{ padding: "8px 0", borderBottom: `1px solid rgba(30,40,64,.4)` }}>
                <span style={{ fontSize: 14 }}>{v.pass ? "✅" : "❌"}</span>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 12, fontWeight: 500, color: v.pass ? C.text : C.textMid }}>{v.label}</div>
                  <div className="text-xs text-mono" style={{ color: v.pass ? C.green : C.red, marginTop: 2 }}>{v.detail}</div>
                </div>
              </div>
            ))}
            <div className="flex gap-8 mt-12">
              <button className="btn btn-primary btn-sm w-full">📄 Generate ROI Report</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── TAB: AI Chat ───────────────────────────────────────────────────────────────
function AIChat() {
  const [messages, setMessages] = useState([
    {
      role: "ai",
      content: "Hello Byron! I'm your BLG Intelligence Assistant. I have full context on your portfolio — Kairoi, Pegasus, Highwoods, Jamestown, and Stonemont.\n\nI can help you analyze contracts, compare vendors, flag opportunities, draft proposals, or surface insights from your pipeline. What do you need?",
    },
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef();

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages]);

  const send = async (text) => {
    const q = text || input.trim();
    if (!q || loading) return;
    setInput("");
    setMessages(m => [...m, { role: "user", content: q }]);
    setLoading(true);

    try {
      const systemPrompt = `You are the BLG Intelligence Assistant, an expert AI for Bottom Line Generation — a commercial real estate cost-optimization consultancy run by Byron, the President/Founder. BLG specializes in telecom, energy, water, IoT, EV charging, and next-gen networking for multi-family communities, commercial offices, student housing, and REITs.

Active clients: Kairoi, Pegasus Residential, Highwoods Properties, Jamestown LP, Stonemont Financial.
Current Bigin pipeline stage: Qualification.
Byron runs parent/child account structures in Bigin CRM.

Portfolio context: 47 analyzed documents, 14 active contracts, 4 vendors in current comparison (Comcast, Lumen, Cox, Brightspeed). Average overspend vs market: $657/mo per property.

Respond as a sharp, data-aware advisor. Be concise but specific. Use numbers where relevant. Keep responses under 200 words. Use markdown-style bold for key figures. Always end with one actionable next step.`;

      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: systemPrompt,
          messages: [
            ...messages.filter(m => m.role !== "typing").map(m => ({ role: m.role === "ai" ? "assistant" : "user", content: m.content })),
            { role: "user", content: q },
          ],
        }),
      });

      const data = await res.json();
      const reply = data.content?.find(b => b.type === "text")?.text || "I encountered an issue. Please try again.";
      setMessages(m => [...m, { role: "ai", content: reply }]);
    } catch {
      setMessages(m => [...m, { role: "ai", content: "Connection issue — please try again." }]);
    }
    setLoading(false);
  };

  return (
    <div>
      <div className="grid-4 mb-16">
        <MetricTile label="AI Queries Today" value="12" color="cyan" />
        <MetricTile label="Insights Generated" value="34" delta="This week" color="purple" />
        <MetricTile label="Docs in Context" value="47" color="gold" />
        <MetricTile label="Model" value="Sonnet" suffix=" 4" color="green" />
      </div>

      <div className="grid-2 gap-20">
        <div className="card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ padding: "16px 20px", borderBottom: `1px solid ${C.border}`, display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{ width: 32, height: 32, borderRadius: 10, background: "linear-gradient(135deg, rgba(0,212,255,.2), rgba(168,85,247,.2))", border: `1px solid rgba(0,212,255,.3)`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16 }}>🤖</div>
            <div>
              <div className="card-title" style={{ marginBottom: 0 }}>BLG Intelligence Assistant</div>
              <div className="text-xs text-mono text-dim">Powered by Claude · Portfolio context active</div>
            </div>
            <div className="flex items-center gap-6" style={{ marginLeft: "auto" }}>
              <div className="pipeline-dot" />
              <span className="text-xs text-mono text-green">Live</span>
            </div>
          </div>

          <div className="chat-messages" style={{ height: 380 }}>
            {messages.map((m, i) => (
              <div key={i} className={`chat-msg ${m.role}`}>
                <div className={`chat-avatar ${m.role}`}>{m.role === "ai" ? "AI" : "B"}</div>
                <div className={`chat-bubble ${m.role}`} style={{ whiteSpace: "pre-wrap", lineHeight: 1.65 }}>
                  {m.content.split(/\*\*(.+?)\*\*/g).map((seg, j) =>
                    j % 2 === 1 ? <strong key={j} style={{ color: C.accent }}>{seg}</strong> : seg
                  )}
                </div>
              </div>
            ))}
            {loading && (
              <div className="chat-msg ai">
                <div className="chat-avatar ai">AI</div>
                <div className="chat-bubble ai">
                  <span className="typing-dot" /><span className="typing-dot" /><span className="typing-dot" />
                </div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>

          <div className="chat-input-row">
            <input
              className="chat-input"
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === "Enter" && !e.shiftKey && send()}
              placeholder="Ask about your portfolio, contracts, savings opportunities..."
            />
            <button className="btn btn-primary" onClick={() => send()} disabled={loading || !input.trim()}>
              {loading ? "..." : "Send ↑"}
            </button>
          </div>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div className="card">
            <div className="card-header"><div className="card-title">Quick Prompts</div><div className="card-sub">One-click analysis starters</div></div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {CHAT_STARTERS.map((s, i) => (
                <button key={i} className="btn btn-secondary w-full" style={{ justifyContent: "flex-start", fontSize: 12, textAlign: "left" }} onClick={() => send(s)}>
                  💬 {s}
                </button>
              ))}
            </div>
          </div>
          <div className="card">
            <div className="card-header"><div className="card-title">Context Active</div></div>
            {[
              ["Portfolio", "5 active clients", "green"],
              ["Pipeline", "Qualification stage", "gold"],
              ["Documents", "47 analyzed", "cyan"],
              ["Contracts", "14 active", "cyan"],
              ["Vendors", "4 in comparison", "purple"],
            ].map(([k, v, c], i) => (
              <div key={i} className="flex items-center justify-between" style={{ padding: "7px 0", borderBottom: i < 4 ? `1px solid rgba(30,40,64,.4)` : "none" }}>
                <span className="text-sm text-mid">{k}</span>
                <span className={`badge badge-${c}`}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

