function loadScript(src) {
  return new Promise((res, rej) => {
    if (document.querySelector(`script[src="${src}"]`)) { res(); return; }
    const s = document.createElement("script");
    s.src = src; s.onload = res; s.onerror = rej;
    document.head.appendChild(s);
  });
}

async function generatePDF(sections) {
  await loadScript("https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js");
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
  const W = 210; const H = 297;
  const margin = 18;
  let y = 0;

  const addPage = () => { doc.addPage(); y = 24; };
  const checkY = (needed = 20) => { if (y + needed > H - 20) addPage(); };

  // ── Cover page ──
  doc.setFillColor(10, 13, 20);
  doc.rect(0, 0, W, H, "F");
  doc.setFillColor(0, 212, 255, 0.08 * 255);

  // Accent bar top
  doc.setFillColor(0, 212, 255);
  doc.rect(0, 0, W, 3, "F");

  // Logo area — embed actual BLG logo
  try {
    doc.addImage(BLG_LOGO_MD, "PNG", margin, 36, 48, 48);
  } catch(e) {
    doc.setFontSize(28); doc.setTextColor(0,212,255); doc.setFont("helvetica","bold");
    doc.text("BLG", margin, 54);
  }
  doc.setFontSize(11);
  doc.setTextColor(138, 155, 191);
  doc.setFont("helvetica", "normal");
  doc.text("BOTTOM LINE GENERATION", margin, 90);

  doc.setFontSize(22);
  doc.setTextColor(232, 237, 247);
  doc.setFont("helvetica", "bold");
  doc.text("Portfolio Intelligence", margin, 100);
  doc.text("Report", margin, 114);

  doc.setFontSize(11);
  doc.setTextColor(138, 155, 191);
  doc.setFont("helvetica", "normal");
  doc.text(`Generated: ${new Date().toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" })}`, margin, 130);
  doc.text("Pipeline Stage: Qualification", margin, 138);
  doc.text("Prepared by: Byron M., President & Founder", margin, 146);

  // Divider
  doc.setDrawColor(30, 40, 64);
  doc.setLineWidth(0.5);
  doc.line(margin, 160, W - margin, 160);

  // Metrics row on cover
  const metrics = [["$417K", "Total Savings ID'd"], ["5", "Parent Accounts"], ["17", "Properties"], ["14", "Active Contracts"]];
  metrics.forEach(([val, lbl], i) => {
    const x = margin + i * 44;
    doc.setFontSize(16);
    doc.setTextColor(0, 212, 255);
    doc.setFont("helvetica", "bold");
    doc.text(val, x, 180);
    doc.setFontSize(8);
    doc.setTextColor(74, 85, 120);
    doc.setFont("helvetica", "normal");
    doc.text(lbl, x, 187);
  });

  // Bottom accent
  doc.setFillColor(0, 212, 255);
  doc.rect(0, H - 2, W, 2, "F");

  // ── Page 2: Executive Summary ──
  if (sections.summary) {
    addPage();
    doc.setFillColor(10, 13, 20); doc.rect(0, 0, W, H, "F");
    doc.setFillColor(0, 212, 255); doc.rect(0, 0, W, 1.5, "F");

    doc.setFontSize(7); doc.setTextColor(74, 85, 120); doc.setFont("helvetica", "normal");
    doc.text("BOTTOM LINE GENERATION  ·  CONFIDENTIAL", margin, 10);
    doc.text(`Page 2`, W - margin, 10, { align: "right" });

    y = 24;
    doc.setFontSize(16); doc.setTextColor(0, 212, 255); doc.setFont("helvetica", "bold");
    doc.text("Executive Summary", margin, y); y += 10;

    doc.setFontSize(10); doc.setTextColor(138, 155, 191); doc.setFont("helvetica", "normal");
    const summaryText = "Bottom Line Generation has identified $417,000 in annualized savings opportunities across 5 parent accounts and 17 managed properties. Current pipeline stage is Qualification with 3 active proposals pending. Vendor analysis across 4 carriers recommends Lumen Technologies for lowest TCO over 36 and 60 month terms.";
    const lines = doc.splitTextToSize(summaryText, W - margin * 2);
    doc.text(lines, margin, y); y += lines.length * 5 + 8;

    // KPI grid
    const kpis = [
      ["$417,000", "Total Annual Savings", C.green],
      ["$2,847", "Avg Current MRR", C.accent],
      ["$2,650", "Benchmark MRR", C.gold],
      ["94%", "Avg Doc Confidence", C.purple],
    ];
    kpis.forEach(([val, lbl, color], i) => {
      const col = i % 2; const row = Math.floor(i / 2);
      const bx = margin + col * 87; const by = y + row * 22;
      doc.setFillColor(22, 28, 45); doc.roundedRect(bx, by - 4, 82, 18, 2, 2, "F");
      doc.setFontSize(14); doc.setTextColor(...hexToRgb(color)); doc.setFont("helvetica", "bold");
      doc.text(val, bx + 6, by + 7);
      doc.setFontSize(8); doc.setTextColor(74, 85, 120); doc.setFont("helvetica", "normal");
      doc.text(lbl, bx + 6, by + 13);
    });
    y += 52;
  }

  // ── Page 3: Client Portfolio ──
  if (sections.portfolio) {
    addPage();
    doc.setFillColor(10, 13, 20); doc.rect(0, 0, W, H, "F");
    doc.setFillColor(0, 212, 255); doc.rect(0, 0, W, 1.5, "F");
    doc.setFontSize(7); doc.setTextColor(74, 85, 120); doc.setFont("helvetica", "normal");
    doc.text("BOTTOM LINE GENERATION  ·  CONFIDENTIAL", margin, 10);

    y = 24;
    doc.setFontSize(16); doc.setTextColor(0, 212, 255); doc.setFont("helvetica", "bold");
    doc.text("Client Portfolio", margin, y); y += 12;

    const colW = [52, 30, 22, 24, 30, 20];
    const colX = colW.reduce((acc, w, i) => { acc.push(i === 0 ? margin : acc[i - 1] + colW[i - 1]); return acc; }, []);
    const headers = ["Account", "Type", "Props", "Stage", "Savings", "Score"];

    // Header row
    doc.setFillColor(22, 28, 45); doc.rect(margin, y - 4, W - margin * 2, 10, "F");
    headers.forEach((h, i) => {
      doc.setFontSize(7); doc.setTextColor(74, 85, 120); doc.setFont("helvetica", "bold");
      doc.text(h.toUpperCase(), colX[i] + 2, y + 2);
    });
    y += 10;

    ACCOUNT_HIERARCHY.forEach((a, ri) => {
      checkY(8);
      if (ri % 2 === 0) { doc.setFillColor(16, 21, 32); doc.rect(margin, y - 3, W - margin * 2, 8, "F"); }
      const row = [a.name, a.type.split("·")[0].trim(), String(a.totalProps), a.stage, a.savings, String(a.score)];
      row.forEach((v, i) => {
        doc.setFontSize(8); doc.setTextColor(i === 4 ? 0 : i === 5 ? 0 : 232, i === 4 ? 229 : i === 5 ? (a.score >= 80 ? 229 : a.score >= 70 ? 166 : 77) : 237, i === 4 ? 160 : i === 5 ? (a.score >= 80 ? 160 : a.score >= 70 ? 35 : 106) : 247);
        doc.setFont("helvetica", i === 0 ? "bold" : "normal");
        doc.text(v, colX[i] + 2, y + 2);
      });
      y += 8;
    });
    y += 6;
  }

  // ── Page 4: Vendor TCO ──
  if (sections.vendors) {
    addPage();
    doc.setFillColor(10, 13, 20); doc.rect(0, 0, W, H, "F");
    doc.setFillColor(0, 212, 255); doc.rect(0, 0, W, 1.5, "F");
    doc.setFontSize(7); doc.setTextColor(74, 85, 120);
    doc.text("BOTTOM LINE GENERATION  ·  CONFIDENTIAL", margin, 10);

    y = 24;
    doc.setFontSize(16); doc.setTextColor(0, 212, 255); doc.setFont("helvetica", "bold");
    doc.text("Vendor Comparison Matrix", margin, y); y += 6;
    doc.setFontSize(9); doc.setTextColor(138, 155, 191); doc.setFont("helvetica", "normal");
    doc.text("36-Month Total Cost of Ownership", margin, y); y += 12;

    const vHeaders = ["Vendor", "MRC/Mo", "Install", "Esc%", "36-Mo TCO", "Score"];
    const vColW = [50, 28, 22, 18, 36, 20];
    const vColX = vColW.reduce((acc, w, i) => { acc.push(i === 0 ? margin : acc[i - 1] + vColW[i - 1]); return acc; }, []);

    doc.setFillColor(22, 28, 45); doc.rect(margin, y - 4, W - margin * 2, 10, "F");
    vHeaders.forEach((h, i) => {
      doc.setFontSize(7); doc.setTextColor(74, 85, 120); doc.setFont("helvetica", "bold");
      doc.text(h, vColX[i] + 2, y + 2);
    });
    y += 10;

    const bestTCO = Math.min(...TCO_DATA.vendors.map(v => calcTCO(v, 36)));
    TCO_DATA.vendors.forEach((v, ri) => {
      const tco = calcTCO(v, 36);
      const isBest = tco === bestTCO;
      if (ri % 2 === 0) { doc.setFillColor(16, 21, 32); doc.rect(margin, y - 3, W - margin * 2, 8, "F"); }
      if (isBest) { doc.setFillColor(0, 229, 160, 0.06 * 255); doc.rect(margin, y - 3, W - margin * 2, 8, "F"); }
      const row = [v.name, `$${v.monthly.toLocaleString()}`, v.install === 0 ? "Waived" : `$${v.install}`, `${v.escalation}%`, `$${tco.toLocaleString()}`, `${v.score}/100`];
      row.forEach((val, i) => {
        const isGreen = isBest && (i === 4);
        doc.setFontSize(8); doc.setTextColor(isGreen ? 0 : 232, isGreen ? 229 : 237, isGreen ? 160 : 247);
        doc.setFont("helvetica", i === 0 || isBest ? "bold" : "normal");
        doc.text(val, vColX[i] + 2, y + 2);
      });
      if (isBest) {
        doc.setFontSize(7); doc.setTextColor(0, 229, 160);
        doc.text("★ RECOMMENDED", vColX[5] + 22, y + 2);
      }
      y += 8;
    });
    y += 6;
    doc.setFontSize(8); doc.setTextColor(138, 155, 191); doc.setFont("helvetica", "normal");
    doc.text("BLG Recommendation: Lumen Technologies — lowest 36-mo TCO, best escalation cap. Negotiate install fee waiver.", margin, y);
  }

  // ── Page 5: Contract Terms ──
  if (sections.contracts) {
    addPage();
    doc.setFillColor(10, 13, 20); doc.rect(0, 0, W, H, "F");
    doc.setFillColor(0, 212, 255); doc.rect(0, 0, W, 1.5, "F");
    doc.setFontSize(7); doc.setTextColor(74, 85, 120);
    doc.text("BOTTOM LINE GENERATION  ·  CONFIDENTIAL", margin, 10);

    y = 24;
    doc.setFontSize(16); doc.setTextColor(0, 212, 255); doc.setFont("helvetica", "bold");
    doc.text("Contract Terms Analysis", margin, y); y += 12;

    CONTRACTS.forEach((c, i) => {
      checkY(14);
      const riskColor = c.risk === "high" ? [255, 77, 106] : c.risk === "medium" ? [245, 166, 35] : [0, 229, 160];
      doc.setFillColor(22, 28, 45); doc.roundedRect(margin, y - 4, W - margin * 2, 12, 2, 2, "F");
      doc.setFillColor(...riskColor); doc.roundedRect(margin, y - 4, 3, 12, 1, 1, "F");
      doc.setFontSize(8); doc.setTextColor(138, 155, 191); doc.setFont("helvetica", "bold");
      doc.text(c.term, margin + 7, y + 1);
      doc.setFontSize(9); doc.setTextColor(232, 237, 247); doc.setFont("helvetica", "normal");
      doc.text(c.value, margin + 7, y + 7);
      const riskLabel = c.risk === "high" ? "HIGH RISK" : c.risk === "medium" ? "REVIEW" : "OK";
      doc.setFontSize(7); doc.setTextColor(...riskColor);
      doc.text(riskLabel, W - margin - 2, y + 4, { align: "right" });
      y += 16;
    });
  }

  // ── Page 6: Financial ──
  if (sections.financial) {
    addPage();
    doc.setFillColor(10, 13, 20); doc.rect(0, 0, W, H, "F");
    doc.setFillColor(0, 212, 255); doc.rect(0, 0, W, 1.5, "F");
    doc.setFontSize(7); doc.setTextColor(74, 85, 120);
    doc.text("BOTTOM LINE GENERATION  ·  CONFIDENTIAL", margin, 10);

    y = 24;
    doc.setFontSize(16); doc.setTextColor(0, 212, 255); doc.setFont("helvetica", "bold");
    doc.text("Financial Validation", margin, y); y += 12;

    const finRows = [
      ["Current MRC", "$2,847/mo", false],
      ["Proposed MRC (Lumen)", "$2,650/mo", true],
      ["Monthly Savings", "$197/mo", true],
      ["36-Month Gross Savings", "$7,092", true],
      ["Installation Fee", "$350", false],
      ["Net 36-Month Savings", "$6,742", true],
      ["ROI", "1,927%", true],
      ["Payback Period", "1.8 months", true],
    ];
    finRows.forEach(([label, value, good], i) => {
      checkY(10);
      if (i % 2 === 0) { doc.setFillColor(16, 21, 32); doc.rect(margin, y - 3, W - margin * 2, 8, "F"); }
      doc.setFontSize(9); doc.setTextColor(138, 155, 191); doc.setFont("helvetica", "normal");
      doc.text(label, margin + 4, y + 2);
      doc.setTextColor(good ? 0 : 232, good ? 229 : 237, good ? 160 : 247); doc.setFont("helvetica", "bold");
      doc.text(value, W - margin - 4, y + 2, { align: "right" });
      y += 8;
    });

    y += 8;
    doc.setFillColor(0, 229, 160, 0.08 * 255); doc.roundedRect(margin, y - 4, W - margin * 2, 18, 3, 3, "F");
    doc.setFontSize(10); doc.setTextColor(0, 229, 160); doc.setFont("helvetica", "bold");
    doc.text("✓ DEAL VALIDATED — Score: 96/100 — APPROVED", margin + 6, y + 6);
    doc.setFontSize(8); doc.setTextColor(138, 155, 191); doc.setFont("helvetica", "normal");
    doc.text("All 6 validation checks passed. Recommend proceeding to contract execution.", margin + 6, y + 12);
  }

  doc.save(`BLG_Portfolio_Report_${new Date().toISOString().split("T")[0]}.pdf`);
}

function hexToRgb(hex) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return [r, g, b];
}

